// Basic implementation of a Min-Heap for Dijkstra's algorithm
struct Heap {
    // Stores (distance, node)
    items: Array(Pair(Int64, Int)),
}

impl Heap {
    fn new() -> Heap {
        Heap.{ items: Array(0) }
    }

    fn size(&self) -> Int {
        self.items.len
    }

    fn isEmpty(&self) -> Bool {
        self.items.len == 0
    }

    // Heapify up operation
    fn bubbleUp(&mut self, index: Int) {
        var current = index
        while current > 0 {
            let parent = (current - 1) / 2
            // Compare distances (first element of Pair)
            if self.items[current].0 < self.items[parent].0 {
                self.items.swap(current, parent)
                current = parent
            } else {
                break
            }
        }
    }

    // Heapify down operation
    fn bubbleDown(&mut self, index: Int) {
        var current = index
        let size = self.size()
        while true {
            let left = 2 * current + 1
            let right = 2 * current + 2
            var smallest = current

            // Check left child
            if left < size && self.items[left].0 < self.items[smallest].0 {
                smallest = left
            }

            // Check right child
            if right < size && self.items[right].0 < self.items[smallest].0 {
                smallest = right
            }

            if smallest != current {
                self.items.swap(current, smallest)
                current = smallest
            } else {
                break
            }
        }
    }

    fn insert(&mut self, distance: Int64, node: Int) {
        self.items.push(Pair(distance, node))
        self.bubbleUp(self.items.len - 1)
    }

    fn extractMin(&mut self) -> Pair(Int64, Int) {
        if self.isEmpty() {
            // Should not happen in Dijkstra if handled correctly
            throw "Heap underflow"
        }
        if self.size() == 1 {
            return self.items.pop()!!
        }

        // Swap root with last element, pop last, then bubble down the new root
        self.items.swap(0, self.items.len - 1)
        let min = self.items.pop()!!
        self.bubbleDown(0)
        min
    }
}


// Dijkstra's algorithm implementation
fn dijkstra(n: Int, adj: Array(Array(Pair(Int, Int64)))) -> Array(Int64) {
    var dist = Array(n).fill(INF)
    var heap = Heap.new()

    // Start node is 0 for this implementation, but since we run it N times, 
    // the caller must handle the starting point. 
    // We structure this function to run from a specific source node.
    // For simplicity in usage, we will wrap this call in a loop calling Dijkstra N times.

    // We modify the signature usage slightly to be clearer: run Dijkstra from source 'start_node'
    // The calling function will manage the loop.
    // Since this helper must be clean, we assume it's called within a loop where 'start_node' is known.
    throw "dijkstra helper needs external loop context, cannot be standalone like this."
}


// Refactored Dijkstra to be callable per source node
fn dijkstra_from_source(n: Int, adj: Array(Array(Pair(Int, Int64))), start_node: Int) -> Array(Int64) {
    var dist = Array(n).fill(INF)
    var heap = Heap.new()

    dist[start_node] = 0
    heap.insert(0, start_node)

    while !heap.isEmpty() {
        let (d, u) = heap.extractMin()

        // If we found a shorter path already, skip this outdated entry
        if d > dist[u] {
            continue
        }

        // Explore neighbors
        for &(v, weight) in adj[u] {
            let new_dist = dist[u] + weight

            if new_dist < dist[v] {
                dist[v] = new_dist
                heap.insert(new_dist, v)
            }
        }
    }
    dist
}


def solve(n_long: Int64, prices: Array(Int64), roads: Array(Array(Int64))) : Array(Int64) {
    let N = n_long as Int
    let N_long = n_long

    // 1. Build Adjacency Lists
    // adj_empty[u] = Array of (v, cost)
    let mut adj_empty = Array(N).fill(Array(0))
    // adj_carry[u] = Array of (v, cost * tax)
    let mut adj_carry = Array(N).fill(Array(0))

    for road in roads {
        // road = [u_i, v_i, cost_i, tax_i]
        let u = road[0] as Int
        let v = road[1] as Int
        let cost = road[2]
        let tax = road[3]

        // Calculate carry cost safely using Int64
        let carry_cost = cost * tax

        // Bidirectional roads

        // Empty travel (Cost = C)
        adj_empty[u].push(Pair(v, cost))
        adj_empty[v].push(Pair(u, cost))

        // Carrying travel (Cost = C * T)
        adj_carry[u].push(Pair(v, carry_cost))
        adj_carry[v].push(Pair(u, carry_cost))
    }

    // 2. Calculate All-Pairs Shortest Paths (APSP)
    // DistE[i][j] = D_empty(i, j)
    var DistE = Array(N).fill(Array(N).fill(INF))
    // DistC[i][j] = D_carry(i, j)
    var DistC = Array(N).fill(Array(N).fill(INF))

    // Calculate DistE: Run Dijkstra N times on the empty graph
    for i in 0..<N {
        let dist_i = dijkstra_from_source(N, adj_empty, i)
        for j in 0..<N {
            DistE[i][j] = dist_i[j]
        }
    }

    // Calculate DistC: Run Dijkstra N times on the carry graph
    for i in 0..<N {
        let dist_i = dijkstra_from_source(N, adj_carry, i)
        for j in 0..<N {
            DistC[i][j] = dist_i[j]
        }
    }

    // 3. Calculate the minimum cost for each shop i
    let mut ans = Array(N).fill(INF)

    for i in 0..<N {
        // Option 1: Buy locally
        var min_cost = prices[i]

        // Option 2: Buy at j, return to i
        for j in 0..<N {
            // Travel i -> j empty, Buy Pj, Travel j -> i carrying

            let travel_empty = DistE[i][j]
            let travel_carry = DistC[j][i]

            // Only consider paths if they exist
            if travel_empty != INF && travel_carry != INF {
                // Total cost = D_empty(i, j) + P_j + D_carry(j, i)
                // P_j is prices[j] (Int64)
                let total_cost = travel_empty + prices[j] + travel_carry

                if total_cost < min_cost {
                    min_cost = total_cost
                }
            }
        }
        ans[i] = min_cost
    }

    return ans
}
